const LOGO_B64 = 'data:image/png;base64,';

const LOGO_ESC_POS_B64 = ''; // ← paste pre-rasterized base64 here (optional)

// ─────────────────────────────────────────────────────────────────────────────
// ESC/POS constants
// ─────────────────────────────────────────────────────────────────────────────
const ESC_INIT         = '\x1b\x40';
const ESC_ALIGN_LEFT   = '\x1b\x61\x00';
const ESC_ALIGN_CENTER = '\x1b\x61\x01';
const ESC_ALIGN_RIGHT  = '\x1b\x61\x02';
const ESC_BOLD_ON      = '\x1b\x45\x01';
const ESC_BOLD_OFF     = '\x1b\x45\x00';
const ESC_DOUBLE_ON    = '\x1b\x21\x30';
const ESC_DOUBLE_OFF   = '\x1b\x21\x00';
const ESC_FEED_CUT     = '\x1d\x56\x41\x03';
const LF               = '\n';
const COL_WIDTH        = 40;
const DASHES           = '-'.repeat(COL_WIDTH);
const DOTS             = '- - - - - - - - - - - - - - - - - - - -';

// ─────────────────────────────────────────────────────────────────────────────
// Helpers
// ─────────────────────────────────────────────────────────────────────────────
function fmt(n: number) {
  return n.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

function padEnd(str: string, len: number): string {
  if (str.length >= len) return str.slice(0, len);
  return str + ' '.repeat(len - str.length);
}

function padStart(str: string, len: number): string {
  if (str.length >= len) return str.slice(-len);
  return ' '.repeat(len - str.length) + str;
}

// ─────────────────────────────────────────────────────────────────────────────
// Logo: decode pre-rasterized ESC/POS binary from base64 (Option A — instant)
// ─────────────────────────────────────────────────────────────────────────────
function getPreRasterizedLogoCmd(): string {
  if (!LOGO_ESC_POS_B64) return '';
  try {
    const clean = LOGO_ESC_POS_B64.replace(/^data:image\/\w+;base64,/, '');
    return atob(clean);
  } catch {
    return '';
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Logo: runtime rasterization from LOGO_B64 (Option B)
// Converts PNG base64 → 1-bit raster → GS v 0 ESC/POS command.
// Result is cached after first call.
// ─────────────────────────────────────────────────────────────────────────────
let _runtimeLogoCache: string | null = null;

async function buildEscPosLogoRuntime(base64: string): Promise<string> {
  if (_runtimeLogoCache !== null) return _runtimeLogoCache;

  try {
    const clean    = base64.replace(/^data:image\/\w+;base64,/, '');
    const TARGET_W = 384; // full width on 80mm @ 203dpi

    // Render a self-contained HTML page that:
    //  1. Draws the image on a <canvas> at TARGET_W
    //  2. Thresholds pixels to 1-bit
    //  3. Builds the GS v 0 raster command
    //  4. Writes the result (base64) into the page <title>
    //
    // We then extract it via a temp file + custom URL scheme trick.
    const html = `<!DOCTYPE html>
<html><head><meta charset="UTF-8"/></head><body>
<canvas id="c"></canvas>
<div id="out" style="word-break:break-all;font-size:1px;color:transparent;"></div>
<script>
(function(){
  var W=${TARGET_W};
  var img=new Image();
  img.onload=function(){
    var s=W/img.width, h=Math.round(img.height*s);
    var cv=document.getElementById('c');
    cv.width=W; cv.height=h;
    var ctx=cv.getContext('2d');
    ctx.fillStyle='#fff'; ctx.fillRect(0,0,W,h);
    ctx.drawImage(img,0,0,W,h);
    var d=ctx.getImageData(0,0,W,h).data;
    var bpr=Math.ceil(W/8);
    var r=new Uint8Array(bpr*h);
    for(var y=0;y<h;y++){
      for(var x=0;x<W;x++){
        var i=(y*W+x)*4;
        var g=0.299*d[i]+0.587*d[i+1]+0.114*d[i+2];
        if(g<128) r[y*bpr+Math.floor(x/8)]|=(0x80>>(x%8));
      }
    }
    var xL=bpr&0xff,xH=(bpr>>8)&0xff,yL=h&0xff,yH=(h>>8)&0xff;
    var hdr=[0x1d,0x76,0x30,0x00,xL,xH,yL,yH];
    var full=new Uint8Array(hdr.length+r.length);
    full.set(hdr,0); full.set(r,hdr.length);
    var bin=''; for(var j=0;j<full.length;j++) bin+=String.fromCharCode(full[j]);
    var b64=btoa(bin);
    document.getElementById('out').textContent=b64;
    document.title='ESCPOS:'+b64;
  };
  img.src='data:image/png;base64,${clean}';
})();
</script></body></html>`;

    // Write to a temp file so expo-print can load it
    const tmpPath = `${FileSystem.cacheDirectory}logo_raster_tmp.html`;
    await FileSystem.writeAsStringAsync(tmpPath, html, {
      encoding: FileSystem.EncodingType.UTF8,
    });

    // expo-print renders headlessly; we can't directly read canvas output.
    // This path is a best-effort — for guaranteed results, use LOGO_ESC_POS_B64.
    void tmpPath;
    throw new Error('Use LOGO_ESC_POS_B64 for reliable thermal printing.');
  } catch {
    _runtimeLogoCache = '';
    return '';
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Master logo getter — returns pre-rasterized ESC/POS logo or empty string
// ─────────────────────────────────────────────────────────────────────────────
async function getLogoEscPosCmd(): Promise<string> {
  const preRasterized = getPreRasterizedLogoCmd();
  if (preRasterized) return preRasterized;
  return '';
}

// ─────────────────────────────────────────────────────────────────────────────
// ESC/POS invoice builder (async — awaits logo)
// ─────────────────────────────────────────────────────────────────────────────
async function buildEscPosInvoice(sale: Sale): Promise<string> {
  const dateStr = new Date(sale.date).toLocaleDateString('fr-MA', {
    day: '2-digit', month: '2-digit', year: 'numeric',
  });
  const subtotal  = sale.items.reduce((s, i) => s + i.qty * i.price, 0);
  const remaining = sale.amount - sale.paid;
  const returnAmt = sale.returnAmount || 0;
  const statusLabel =
    sale.status === 'paid'    ? 'PAYE'    :
    sale.status === 'partial' ? 'PARTIEL' : 'IMPAYE';

  // ── Summary line helper (label left, value right, total 40 chars) ─────────
  const TOTAL_WIDTH = 40;
  const summaryLine = (label: string, value: string, bold = false): string => {
    const line = padEnd(label, TOTAL_WIDTH - value.length) + value;
    return bold
      ? ESC_BOLD_ON + line + ESC_BOLD_OFF + LF
      : line + LF;
  };

  // ── Value line helper: aligns MAD values to the right column ──────────────
  const RIGHT_COL_WIDTH = 45;
  const valueLine = (label: string, value: string, bold = false): string => {
    const valueStr = value + ' MAD';
    const spaces = RIGHT_COL_WIDTH - label.length - valueStr.length;
    const line = label + ' '.repeat(Math.max(1, spaces)) + valueStr + LF;
    return bold
      ? ESC_BOLD_ON + line + ESC_BOLD_OFF
      : line;
  };

  let doc = '';
  doc += ESC_INIT;
  doc += ESC_ALIGN_CENTER;

  // ── Header ──────────────────────────────────────────────────────────────────
  const logoCmd = await getLogoEscPosCmd();
  if (logoCmd) {
    doc += logoCmd + LF;
  } else {
    doc += ESC_DOUBLE_ON + 'FLURRY' + ESC_DOUBLE_OFF + LF;
  }
  doc += DOTS + LF;
  doc += ESC_BOLD_ON + `FACTURE #${sale.invoiceNumber}` + ESC_BOLD_OFF + LF;
  doc += DASHES + LF;

  // ── Meta + Bill-to (side by side, separated by |) ─────────────────────────
  doc += ESC_ALIGN_LEFT;
  doc += padEnd('Date:', 10)      + padEnd(dateStr.slice(0, 10), 10) + '  |  ' + ESC_BOLD_ON + 'CLIENT: ' + ESC_BOLD_OFF + sale.customerName.slice(0, 12) + LF;
  doc += padEnd('Vendeur:', 10)   + padEnd((sale.vendeur || '-').slice(0, 10), 10) + '  |  ' + (sale.customerPhone || '').slice(0, 19) + LF;
  doc += padEnd('Reglement:', 10) + padEnd(sale.paymentMethod.slice(0, 10), 10)    + '  |  ' + LF;
  doc += DASHES + LF;

  // ── Items header ──────────────────────────────────────────────────────────
  doc += ESC_BOLD_ON;
  doc += padEnd('ARTICLE', 18)
       + '   ' + padEnd('QTE', 4)
       + '   ' + padStart('P.U.', 7)
       + '   ' + padStart('TOTAL', 7) + LF;
  doc += ESC_BOLD_OFF;
  doc += DASHES + LF;

  // ── Items rows ────────────────────────────────────────────────────────────
  for (const item of sale.items) {
    const lineTotal = item.qty * item.price;
    const name = item.name.slice(0, 17);
    doc += padEnd(name, 18)
         + '   ' + padEnd(String(item.qty), 4)
         + '   ' + padStart(fmt(item.price), 7)
         + '   ' + padStart(fmt(lineTotal), 7) + LF;
  }
  doc += DASHES + LF;

  // ── Subtotal / discount / return ──────────────────────────────────────────
  doc += ESC_ALIGN_LEFT;
  doc += valueLine('Sous-total:', fmt(subtotal));

  if (sale.discount > 0) {
    const disc = subtotal * sale.discount / 100;
    doc += valueLine('Remise (' + sale.discount + '%):', '- ' + fmt(disc));
  }

  if (returnAmt > 0) {
    doc += valueLine('Retour:', '- ' + fmt(returnAmt));
  }

  // ── Grand total ───────────────────────────────────────────────────────────
  doc += DASHES + LF;
  doc += ESC_ALIGN_CENTER;
  doc += ESC_BOLD_ON + ESC_DOUBLE_ON;
  doc += 'TOTAL: ' + fmt(sale.amount) + ' MAD';
  doc += ESC_DOUBLE_OFF + ESC_BOLD_OFF + LF;
  doc += DASHES + LF;

  // ── Payment summary ───────────────────────────────────────────────────────
  doc += ESC_ALIGN_LEFT;
  doc += valueLine('Paye:', fmt(sale.paid));

  if (remaining > 0) {
    doc += valueLine('Reste a payer:', fmt(remaining), true);
  }

  // ── Status ────────────────────────────────────────────────────────────────
  doc += ESC_ALIGN_CENTER;
  doc += DOTS + LF;
  doc += ESC_BOLD_ON + `[ ${statusLabel} ]` + ESC_BOLD_OFF + LF;
  doc += DOTS + LF;

  // ── Footer ────────────────────────────────────────────────────────────────
  doc += 'Merci pour votre confiance!' + LF;
  doc += LF + LF + LF;
  doc += ESC_FEED_CUT;
  doc += DOTS + LF;
  return doc;
}

// ─────────────────────────────────────────────────────────────────────────────
// ESC/POS transfer builder
// ─────────────────────────────────────────────────────────────────────────────
function buildEscPosTransfer(transfer: Transfer): string {
  let doc = ESC_INIT;

  doc += ESC_ALIGN_CENTER;
  doc += ESC_BOLD_ON + 'TRANSFERT STOCK' + ESC_BOLD_OFF + LF;
  doc += DASHES + LF;

  doc += ESC_ALIGN_LEFT;
  doc += padEnd('Ref:', 16) + transfer.ref + LF;
  doc += padEnd('Date:', 16) + new Date(transfer.date).toLocaleString('fr-MA') + LF;
  doc += padEnd('De:', 16) + transfer.from + LF;
  doc += padEnd('Vers:', 16) + transfer.to + LF;
  doc += DASHES + LF;

  doc += ESC_BOLD_ON;
  doc += padEnd('ARTICLE', 22) + padEnd('QTE', 6) + padStart('TOTAL', 12) + LF;
  doc += ESC_BOLD_OFF;
  doc += DASHES + LF;

  for (const i of transfer.items) {
    const t = i.qty * (parseFloat(i.unit) || 0);
    doc += padEnd(i.name.slice(0, 21), 22)
         + padEnd(String(i.qty), 6)
         + padStart(`${fmt(t)} MAD`, 12) + LF;
  }

  doc += DASHES + LF;
  doc += ESC_BOLD_ON;
  doc += padEnd('TOTAL:', 28) + padStart(`MAD ${fmt(transfer.total)}`, 12) + LF;
  doc += ESC_BOLD_OFF;

  doc += LF + LF + LF + ESC_FEED_CUT;
  return doc;
}

// ─────────────────────────────────────────────────────────────────────────────
// ESC/POS daily summary builder
// ─────────────────────────────────────────────────────────────────────────────
async function buildEscPosDailySummary(data: DailySummaryData): Promise<string> {
  const today = new Date().toLocaleDateString('fr-MA', {
    day: '2-digit', month: '2-digit', year: 'numeric',
  });

  const RIGHT_COL_WIDTH = 42;
  const valueLine = (label: string, value: string, bold = false): string => {
    const valueStr =   value + ' MAD';
    const spaces = RIGHT_COL_WIDTH - label.length - valueStr.length;
    const line = label + ' '.repeat(Math.max(1, spaces)) + valueStr + LF;
    return bold ? ESC_BOLD_ON + line + ESC_BOLD_OFF : line;
  };

  const metaLine = (label: string, value: string): string => {
    return padEnd(label, 14) + value + LF;
  };

  let doc = ESC_INIT;

  // ── Header ─────────────────────────────────────────────────────────────────
  doc += ESC_ALIGN_CENTER;
  const logoCmd = await getLogoEscPosCmd();
  if (logoCmd) {
    doc += logoCmd + LF;
  } else {
    doc += ESC_DOUBLE_ON + 'FLURRY' + ESC_DOUBLE_OFF + LF;
  }
  doc += DOTS + LF;
  doc += ESC_BOLD_ON + 'RESUME JOURNALIER' + ESC_BOLD_OFF + LF;
  doc += DASHES + LF;

  // ── Informations ───────────────────────────────────────────────────────────
  doc += ESC_ALIGN_LEFT;
  doc += metaLine('Date:', today);
  doc += metaLine('Periode:', data.periodLabel);
  if (data.vendorName) doc += metaLine('Vendeur:', data.vendorName);
  if (data.truckLabel) doc += metaLine('Camion:', data.truckLabel);
  doc += DASHES + LF;

  // ── Financier ──────────────────────────────────────────────────────────────
  doc += valueLine('Total ventes:', fmt(data.totalSales), true);
  doc += DASHES + LF;
  doc += valueLine('Encaisse:', fmt(data.cashCollected));
  doc += valueLine('Credit clients:', fmt(data.customerCredit));
  doc += DASHES + LF;

  // ── Stock & activite ───────────────────────────────────────────────────────
  doc += valueLine('Stock restant:', fmt(data.stockValue));
  doc += valueLine('Nb. factures:', String(data.salesCount));
  doc += DASHES + LF;

  // ── Footer ─────────────────────────────────────────────────────────────────
  doc += ESC_ALIGN_CENTER;
  doc += DOTS + LF;
  doc += `Flurryice - ${today}` + LF;
  doc += LF + LF + LF + ESC_FEED_CUT;

  return doc;
}

